package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetTrailingDelimiter_Default() throws Exception {
        // Default constant DEFAULT has trailingDelimiter = false
        setTrailingDelimiter(CSVFormat.DEFAULT, false);
        assertFalse(CSVFormat.DEFAULT.getTrailingDelimiter());
    }

    @Test
    void testGetTrailingDelimiter_WithTrailingDelimiterTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withTrailingDelimiter(true);
        setTrailingDelimiter(format, true);
        assertTrue(format.getTrailingDelimiter());
    }

    @Test
    void testGetTrailingDelimiter_WithTrailingDelimiterFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withTrailingDelimiter(false);
        setTrailingDelimiter(format, false);
        assertFalse(format.getTrailingDelimiter());
    }

    @Test
    void testGetTrailingDelimiter_OtherConstants() throws Exception {
        // EXCEL inherits from DEFAULT, trailingDelimiter should be false
        setTrailingDelimiter(CSVFormat.EXCEL, false);
        assertFalse(CSVFormat.EXCEL.getTrailingDelimiter());
        // INFORMIX_UNLOAD inherits from DEFAULT, trailingDelimiter should be false
        setTrailingDelimiter(CSVFormat.INFORMIX_UNLOAD, false);
        assertFalse(CSVFormat.INFORMIX_UNLOAD.getTrailingDelimiter());
        // MYSQL inherits from DEFAULT, trailingDelimiter should be false
        setTrailingDelimiter(CSVFormat.MYSQL, false);
        assertFalse(CSVFormat.MYSQL.getTrailingDelimiter());
        // POSTGRESQL_CSV inherits from DEFAULT, trailingDelimiter should be false
        setTrailingDelimiter(CSVFormat.POSTGRESQL_CSV, false);
        assertFalse(CSVFormat.POSTGRESQL_CSV.getTrailingDelimiter());
        // TDF inherits from DEFAULT, trailingDelimiter should be false
        setTrailingDelimiter(CSVFormat.TDF, false);
        assertFalse(CSVFormat.TDF.getTrailingDelimiter());
    }

    private void setTrailingDelimiter(CSVFormat format, boolean value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("trailingDelimiter");
        field.setAccessible(true);
        field.setBoolean(format, value);
    }
}
